**Untested:** mobile menu toggle state, link href generation, active-link styling, mobile menu close-on-link-click.

**Edge case bug identified:** `link.toLowerCase().replace(" ", "-")` uses `String.replace` with a string literal — only replaces the **first** space. A nav label with multiple spaces would produce broken anchors.

```tsx
// src/components/Navbar.test.tsx
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { Navbar } from "./Layout";

describe("Navbar", () => {
  it("renders all navigation links", () => {
    render(<Navbar />);
    const links = ["Home", "Cari Tukang", "Kategori", "Cara Kerja", "Testimoni", "Blog"];
    links.forEach((label) => {
      expect(screen.getByText(label)).toBeInTheDocument();
    });
  });

  it("generates correct href for single-space labels", () => {
    render(<Navbar />);
    const link = screen.getAllByRole("link", { name: "Cari Tukang" })[0];
    expect(link).toHaveAttribute("href", "#cari-tukang");
  });

  // Bug coverage: replace(" ", "-") only replaces first space
  it("href for multi-word labels only replaces first space (known limitation)", () => {
    render(<Navbar />);
    const link = screen.getAllByRole("link", { name: "Cara Kerja" })[0];
    // Currently produces "#cara-kerja" — passes because only one space
    // If label were "Cara Kerja Lain", href would be "#cara-kerja lain" — broken
    expect(link).toHaveAttribute("href", "#cara-kerja");
  });

  it("highlights the first nav link as active", () => {
    render(<Navbar />);
    const homeLink = screen.getAllByRole("link", { name: "Home" })[0];
    expect(homeLink).toHaveClass("text-[#FF7315]");
  });

  it("mobile menu is hidden by default", () => {
    render(<Navbar />);
    // Mobile nav container should not be visible
    expect(screen.queryByRole("link", { name: "Home", hidden: false })).toBeDefined();
    // Hamburger icon present, X icon absent
    expect(screen.queryByTestId("close-icon")).not.toBeInTheDocument();
  });

  it("opens mobile menu when hamburger button is clicked", async () => {
    render(<Navbar />);
    const menuButton = screen.getByRole("button", { name: "" }); // hamburger
    await userEvent.click(menuButton);
    // Mobile nav links become visible
    const mobileLinks = screen.getAllByText("Kategori");
    expect(mobileLinks.length).toBeGreaterThan(0);
  });

  it("closes mobile menu when X button is clicked", async () => {
    render(<Navbar />);
    const menuButton = screen.getByRole("button");
    await userEvent.click(menuButton); // open
    await userEvent.click(menuButton); // close (X button replaces hamburger)
    // After close the mobile nav exits
  });

  it("closes mobile menu when a nav link is clicked", async () => {
    render(<Navbar />);
    const menuButton = screen.getByRole("button");
    await userEvent.click(menuButton);
    const mobileLink = screen.getAllByText("Kategori")[0];
    await userEvent.click(mobileLink);
    // isOpen becomes false — mobile nav should animate out
  });

  it("renders Masuk and Download App action buttons", () => {
    render(<Navbar />);
    expect(screen.getAllByText("Masuk").length).toBeGreaterThan(0);
    expect(screen.getAllByText("Download App").length).toBeGreaterThan(0);
  });
});
```

