      expect(screen.getAllByText(label)[0]).toBeInTheDocument();
    });
  });

  it("renders Company section links", () => {
    render(<Footer />);
    ["Tentang Kami", "Karir", "Blog", "Kontak"].forEach((label) => {
      expect(screen.getByText(label)).toBeInTheDocument();
    });
  });

  it("renders Support section links", () => {
    render(<Footer />);
    ["FAQ", "Pusat Bantuan", "Syarat & Ketentuan", "Kebijakan Privasi"].forEach((label) => {
      expect(screen.getByText(label)).toBeInTheDocument();
    });
  });

  it("renders newsletter email input", () => {
    render(<Footer />);
    expect(screen.getByPlaceholderText(/masukkan email/i)).toBeInTheDocument();
  });

  it("renders newsletter submit button", () => {
    render(<Footer />);
    expect(screen.getByRole("button", { name: /kirim/i })).toBeInTheDocument();
  });

  // Missing error handling: no validation on empty/invalid email submission
  it("does not validate empty email on submit (gap: no validation)", async () => {
    render(<Footer />);
    const button = screen.getByRole("button", { name: /kirim/i });
    await userEvent.click(button);
    // No error message appears — validation is absent
    expect(screen.queryByText(/email tidak valid/i)).not.toBeInTheDocument();
  });

  it("does not validate malformed email (gap: no validation)", async () => {
    render(<Footer />);
    const input = screen.getByPlaceholderText(/masukkan email/i);
    await userEvent.type(input, "not-an-email");
    await userEvent.click(screen.getByRole("button", { name: /kirim/i }));
    expect(screen.queryByText(/email tidak valid/i)).not.toBeInTheDocument();
  });

  it("renders 4 social media icon links", () => {
    render(<Footer />);
    const socialLinks = screen.getAllByRole("link").filter(
      (el) => el.getAttribute("href") === "#"
    );
    // Social + footer nav links all point to "#"; social icons are the first 4
    expect(socialLinks.length).toBeGreaterThanOrEqual(4);
